+    public static Event dispatch(Event event, EventDispatcher dispatcher) {
+        if (dispatcher == null || event == null) {
+            return null;
+        }
+        var chain = new EventDispatchChainImpl();
+        chain.append(dispatcher);
+        return chain.dispatchEvent(event);
+    }

